// =============================================================================
// Internal constants — not exposed in the header
// =============================================================================

/**
 * @brief   Maximum number of entries in the 100 ms CAN ring buffer.
 * @details Sized to hold 10 seconds of 100 ms samples (100 entries) providing
 *          the full pre-trigger retention window at the 100 ms sampling rate.
 *          Range: fixed at 100 entries.
 */
static constexpr uint32_t kMaxBuffer100ms{100U};

/**
 * @brief   Maximum number of entries in the 1000 ms CAN ring buffer.
 * @details Sized to hold 10 seconds of 1000 ms samples (10 entries) providing
 *          the full pre-trigger retention window at the 1000 ms sampling rate.
 *          Range: fixed at 10 entries.
 */
static constexpr uint32_t kMaxBuffer1000ms{10U};

/**
 * @brief   Default past data retention count for the log data set rolling buffer.
 * @details Configures the rolling log buffer to retain 10 per-second log data sets,
 *          corresponding to a 10-second pre-trigger history window per SWR-REQ-03-01-009.
 */
static constexpr uint32_t kDefaultPastDataRetentionCount{10U};

/**
 * @brief   Capacity reservation for the 100 ms steady-state staging buffer.
 * @details Pre-allocated to avoid runtime heap growth during cyclic execution.
 *          Sized for a single serialised 100 ms CAN frame (256 bytes typical).
 */
static constexpr std::size_t kSteadyState100msReserve{256U};

/**
 * @brief   Capacity reservation for the 1000 ms steady-state staging buffer.
 * @details Pre-allocated to avoid runtime heap growth during cyclic execution.
 *          Sized for a single serialised 1000 ms CAN frame (512 bytes typical).
 */
static constexpr std::size_t kSteadyState1000msReserve{512U};

/**
 * @brief   Capacity reservation for the event sending buffer.
 * @details Pre-allocated to avoid runtime heap growth during event processing.
 *          Sized for a typical event payload (1024 bytes).
 */
static constexpr std::size_t kEventSendingBufferReserve{1024U};

/**
 * @brief   Capacity reservation for the image data buffer.
 * @details Pre-allocated to avoid runtime heap growth during image acquisition.
 *          Sized for a compressed camera frame (65536 bytes typical).
 */
static constexpr std::size_t kImageDataBufferReserve{65536U};

// =============================================================================
// Internal helper: obtain a monotonic timestamp in seconds (uint32_t)
// =============================================================================

/**
 * @brief   Returns the current monotonic clock value in seconds.
 * @details Uses std::chrono::steady_clock to obtain a monotonic, non-adjustable
 *          timestamp. The value is cast to uint32_t; wrap-around after ~136 years
 *          is acceptable for startup-delay enforcement purposes.
 * @return  Current monotonic time in whole seconds as uint32_t.
 * @throws  None — noexcept.
 */
static uint32_t GetTimestampSeconds() noexcept
{
    const auto now{std::chrono::steady_clock::now().time_since_epoch()};
    const uint64_t seconds{static_cast<uint64_t>(
        std::chrono::duration_cast<std::chrono::seconds>(now).count())};
    return static_cast<uint32_t>(seconds & 0xFFFFFFFFU);
}

/**
 * @brief   Returns the current monotonic clock value in milliseconds.
 * @details Uses std::chrono::steady_clock to obtain a monotonic timestamp in
 *          milliseconds. Used for cycle-boundary enforcement in Run().
 * @return  Current monotonic time in whole milliseconds as uint64_t.
 * @throws  None — noexcept.
 */
static uint64_t GetTimestampMs() noexcept
{
    const auto now{std::chrono::steady_clock::now().time_since_epoch()};
    return static_cast<uint64_t>(
        std::chrono::duration_cast<std::chrono::milliseconds>(now).count());
}

