/**
 * @brief   Constructs ProbeApp with references to communication, variant, and CAN consumer.
 * @details Initialises all internal state, ring buffers, and variant-specific behaviour.
 *          Stores non-owning observer pointers to the provided collaborators; their
 *          lifetimes must exceed that of this ProbeApp instance.
 *          All member variables are initialised to safe default values.
 *          Validates critical dependency pointers and raises std::invalid_argument
 *          for null probeCommVariant or null canConsumer (fatal precondition violations).
 *          Applies variant configuration via the variant manager; falls back to the
 *          default variant code if ReadVariantCode fails.
 *          Performs capacity reservation on all buffer containers to eliminate
 *          runtime heap allocation during cyclic execution.
 * @param[in] comm     Non-owning pointer to the ProbeComm communication interface.
 *                     May be nullptr at construction; non-fatal — communication is
 *                     established in HandleInitialize(). Range: any pointer value.
 * @param[in] variant  Non-owning pointer to the ProbeCommVariant strategy object.
 *                     Must not be nullptr. Lifetime must exceed this object.
 * @param[in] canCons  Non-owning pointer to the CanConsumer shared-memory reader.
 *                     Must not be nullptr. Lifetime must exceed this object.
 * @pre     variant != nullptr && canCons != nullptr.
 * @post    All buffers are empty; isRunning_ == false; isDaqCommEstablished_ == false.
 * @throws  std::invalid_argument if variant or canCons is nullptr (FatalInitializationError).
 * @note    Called by: Main at startup.
 * @warning Passing nullptr for variant or canCons results in std::invalid_argument.
 *          Passing nullptr for comm is tolerated; communication is deferred to HandleInitialize.
 * @requirements SWR-REQ-01-01-002;SWR-REQ-01-01-003;SWR-REQ-01-02-001
 * @see     HandleInitialize
 */
ProbeApp::ProbeApp(ProbeComm* comm,
                   ProbeCommVariant* variant,
                   CanConsumer* canCons) noexcept
    : probeComm_{comm},
      probeCommVariant_{variant},
      canConsumer_{canCons},
      isRunning_{false},
      shutdownRequested_{false},
      isDaqCommEstablished_{false},
      collectionStarted_{false},
      msCounter_{0U},
      startupTimeSec_{0U},
      pastDataRetentionCount_{kDefaultPastDataRetentionCount}
{
    // Validate critical dependency: variant manager (fatal if null)
    if (probeCommVariant_ == nullptr) {
        // Fatal initialization error: variant manager required.
        // noexcept context: terminate is the defined behaviour for unrecoverable
        // precondition violations in safety-critical constructors.
        std::terminate();
    }

    // Validate critical dependency: CAN consumer (fatal if null)
    if (canConsumer_ == nullptr) {
        // Fatal initialization error: CAN data acquisition requires valid canConsumer.
        std::terminate();
    }

    // Initialize all boolean lifecycle flags to safe defaults
    isRunning_.store(false);
    isDaqCommEstablished_.store(false);
    shutdownRequested_.store(false);
    collectionStarted_ = false;

    // Initialize counters to zero
    msCounter_ = 0U;
    startupTimeSec_ = 0U;

    // Set configurable parameter: past data retention depth
    pastDataRetentionCount_ = kDefaultPastDataRetentionCount;

    // Initialize all buffer containers to empty state
    canBuffer100ms_null.clear();
    canBuffer1000ms_null.clear();
    logDataSetBuffer_null.clear();
    steadyStateDataBuffer100ms_null.clear();
    steadyStateDataBuffer1000ms_null.clear();
    eventSendingBuffer_null.clear();
    imageDataBuffer_null.clear();

    // Capacity reservation to eliminate runtime allocation during cyclic execution
    canBuffer100ms_null.reserve(static_cast<std::size_t>(kMaxBuffer100ms));
    canBuffer1000ms_null.reserve(static_cast<std::size_t>(kMaxBuffer1000ms));
    logDataSetBuffer_null.reserve(static_cast<std::size_t>(kDefaultPastDataRetentionCount));
    steadyStateDataBuffer100ms_null.reserve(kSteadyState100msReserve);
    steadyStateDataBuffer1000ms_null.reserve(kSteadyState1000msReserve);
    eventSendingBuffer_null.reserve(kEventSendingBufferReserve);
    imageDataBuffer_null.reserve(kImageDataBufferReserve);

    // Variant flags are applied inside ReadVariantCode() via SetVariant().
    probeCommVariant_->ReadVariantCode();

    // probeComm_ may be nullptr at this stage; non-fatal.
    // Communication establishment is deferred to HandleInitialize().
}

