/**
 * @brief   Destroys the ProbeApp instance and releases all owned resources.
 * @details Ensures all RAII-managed resources (mutexes, buffers) are released
 *          cleanly. Does not perform network communication; HandleShutdown() or
 *          HandleTerminate() must be called before destruction for graceful teardown.
 * @pre     HandleTerminate() or HandleShutdown() has been called.
 * @post    All resources owned by this instance are released.
 * @throws  None.
 */
ProbeApp::~ProbeApp() noexcept = default;

// =============================================================================
// HandleInitialize
// =============================================================================

/**
 * @brief   Starts ProbeApp operation after ADAS ECU startup and initiates SOME/IP
 *          communication with DAQ.
 * @details Reads the variant code from shared memory and applies feature flags or
 *          falls back to the default variant code on failure. Sets isRunning_ to true,
 *          captures the startup reference timestamp, and initiates SOME/IP service
 *          discovery via ProbeComm. The isDaqCommEstablished_ flag is NOT set here;
 *          it is set only when the service discovery handshake completes, which is
 *          monitored within the cyclic Run() context.
 *          If InitiateSomeIpDiscovery fails, isDaqCommEstablished_ remains false and
 *          the Run() loop will retry discovery each cycle.
 * @pre     ProbeApp has been successfully constructed.
 * @post    isRunning_ == true; startupTimeSec_ captures the boot reference timestamp;
 *          SOME/IP service discovery is in progress.
 * @throws  None.
 * @note    Called by: Main after ECU boot sequence completes.
 * @warning Calling this method more than once results in undefined behaviour.
 * @requirements SWR-REQ-01-10-001;SWR-REQ-01-10-002;SWR-REQ-01-03-001;
 *               SWR-REQ-03-16-001;SWR-REQ-03-16-002
 * @see     Run, HandleTerminate
 */
void ProbeApp::HandleInitialize() noexcept
{
    // Step 1: Read variant code from shared memory (applies flags via SetVariant)
    probeCommVariant_->ReadVariantCode();

    // Step 2: Mark application as running
    isRunning_.store(true);

    // Step 3: Capture startup reference timestamp (seconds)
    startupTimeSec_ = GetTimestampSeconds();

    // Step 4: Initiate SOME/IP service discovery with DAQ
    // isDaqCommEstablished_ remains false until session confirmed in Run()
    if (probeComm_ != nullptr) {
        const bool discoveryResult{probeComm_->InitiateSomeIpDiscovery()};
        if (!discoveryResult) {
            // Non-fatal: Run loop will continue retrying discovery.
            // isDaqCommEstablished_ remains false; data transmission suppressed.
            // No error raised: bounded retry is handled in Run().
        }
    }

    // Step 5: HandleInitialize complete.
    // isRunning_ = true, isDaqCommEstablished_ = false (pending confirmation),
    // startupTimeSec_ captures boot reference for 10-second delay check in Run().
}

// =============================================================================
// Run
// =============================================================================

/**
 * @brief   Runs the cyclic data collection and transmission processing loop.
 * @details Executes the main processing loop. Each iteration represents one 100 ms
 *          execution cycle. The loop:
 *            1. Checks the 10-second startup delay via CheckCollectionStartDelay().
 *            2. When collectionStarted_ is true, invokes CollectSharedMemReadSignals(),
 *               StoreCanData100ms() every cycle, and StoreCanData1000ms() at the
 *               1000 ms boundary (msCounter_ == 0 after reset).
 *            3. Increments msCounter_ by 100 and resets at 1000 to prevent overflow.
 *            4. Transmits steady-state data via SendRegularData() when DAQ session
 *               is established, or attempts re-discovery otherwise.
 *            5. Enforces the 100 ms cycle boundary via std::this_thread::sleep_for().
 *          The loop exits when shutdownRequested_ becomes true or isRunning_ becomes false.
 * @pre     HandleInitialize() has been called successfully.
 * @post    Buffers and transmission state are updated for each cycle until shutdown.
 * @throws  None.
 * @note    Called by: Main cyclic 10 ms task (drives the internal 100 ms loop).
 * @warning Must not be called concurrently from multiple threads.
 * @requirements SWR-REQ-01-001;SWR-REQ-01-002;SWR-REQ-01-005;SWR-REQ-01-06-001;
 *               SWR-REQ-01-10-003;SWR-REQ-03-16-003
 * @see     HandleInitialize, HandleTerminate
 */
void ProbeApp::Run() noexcept
{
    // Enter cyclic execution loop; terminates on shutdown request or stop
    while ((shutdownRequested_.load() == false) && (isRunning_.load() == true)) {

        // Record cycle start time for period enforcement (milliseconds)
        const uint64_t cycleStartTime{GetTimestampMs()};

        // Step 1: Check if startup delay has elapsed and enable collection
        CheckCollectionStartDelay();

        // Step 2: Execute data collection if collection is enabled
        if (collectionStarted_ == true) {

            // Step 2a: Collect signals from shared memory at applicable rates
            CollectSharedMemReadSignals();

            // Step 2b: Store 100 ms rate data every cycle
            StoreCanData100ms();

            // Step 2c: Store 1000 ms rate data only at 1000 ms boundary
            // After CollectSharedMemReadSignals increments msCounter_,
            // msCounter_ == 0 indicates the 1000 ms boundary has been reached.
            if (msCounter_ == 0U) {
                StoreCanData1000ms();
            }

        }
        // else: Startup delay not yet elapsed; skip collection and transmission.

        // Step 3: Transmit steady-state data if DAQ session is confirmed
        if ((isDaqCommEstablished_.load() == true) && (collectionStarted_ == true)) {
            SendRegularData();
        } else if (isDaqCommEstablished_.load() == false) {
            // Attempt to re-establish DAQ communication
            if (probeComm_ != nullptr) {
                const bool reDiscoveryResult{probeComm_->InitiateSomeIpDiscovery()};
                if (reDiscoveryResult == true) {
                    isDaqCommEstablished_.store(true);
                }
            }
            // No data transmitted while session not confirmed
        } else {
            // collectionStarted_ is false; no transmission yet
        }

        // Step 4: Enforce 100 ms cycle boundary
        const uint64_t cycleElapsed{GetTimestampMs() - cycleStartTime};
        const uint64_t kCyclePeriodMs{100U};
        if (cycleElapsed < kCyclePeriodMs) {
            const uint64_t sleepDurationMs{kCyclePeriodMs - cycleElapsed};
            std::this_thread::sleep_for(
                std::chrono::milliseconds(static_cast<int64_t>(sleepDurationMs)));
        }
        // If cycleElapsed >= 100, next cycle starts immediately
    }

    // Loop exited: shutdown or stop requested.
    // Cleanup performed by HandleTerminate().
}

// =============================================================================
// HandleTerminate
// =============================================================================

/**
 * @brief   Stops all data collection and transmission processing on termination.
 * @details Sets shutdownRequested_ to true so that the Run() loop exits on its next
 *          cycle boundary. Sets isRunning_ to false to mark the application as stopped.
 *          Invokes ClearAllTemporaryData() to purge all RAM buffers including any
 *          data in mid-transmission. If ClearAllTemporaryData() reports failure,
 *          HALT_APPLICATION() is invoked to prevent further operation in an
 *          inconsistent state (safety-critical hard stop).
 * @pre     HandleInitialize() has been called.
 * @post    isRunning_ == false; shutdownRequested_ == true; all buffers are empty
 *          on success; application halted on cleanup failure.
 * @throws  None.
 * @note    Called by: Main on ECU termination event.
 * @requirements SWR-REQ-01-09-001;SWR-REQ-03-13-001
 * @see     HandleShutdown, ClearAllTemporaryData
 */
void ProbeApp::HandleTerminate() noexcept
{
    // Step 1: Signal the Run loop to stop on next cycle boundary
    shutdownRequested_.store(true);

    // Step 2: Mark application as no longer running
    isRunning_.store(false);

    // Step 3: Purge all RAM buffers including in-transit data
    ClearAllTemporaryData();

    // Step 4: Verify deletion success
    // ClearAllTemporaryData() is void in the header; we verify by checking
    // that all buffers are empty after the call (post-condition check).
    // If any buffer is non-empty after the purge, initiate hard stop.
    {
        const std::lock_guard<std::mutex> lock100ms{bufferMutex100ms_null};
        const std::lock_guard<std::mutex> lock1000ms{bufferMutex1000ms_null};
        const std::lock_guard<std::mutex> lockLog{logBufferMutex_null};

        const bool allClear{
            canBuffer100ms_null.empty() &&
            canBuffer1000ms_null.empty() &&
            logDataSetBuffer_null.empty() &&
            steadyStateDataBuffer100ms_null.empty() &&
            steadyStateDataBuffer1000ms_null.empty() &&
            eventSendingBuffer_null.empty() &&
            imageDataBuffer_null.empty()
        };

        if (!allClear) {
            // Deletion failed: residual data may contain personal information.
            // Hard stop: prevent further operation in inconsistent state.
            std::terminate();
        }
    }

    // HandleTerminate returns; no further processing.
}

// =============================================================================
// HandleShutdown
// =============================================================================

/**
 * @brief   Stops all processing and deletes all temporary data including
 *          mid-transmission data on ADAS ECU shutdown.
 * @details Evaluates the shutdownRequested_ flag. If shutdown has been requested,
 *          sets isRunning_ to false to halt all cyclic and event-driven processing,
 *          then delegates full buffer purge to ClearAllTemporaryData(). The
 *          cleanupResult is evaluated; if cleanup fails, EnforceStopOnRamCleanupFailure()
 *          is invoked unconditionally to force a controlled application halt.
 *          If shutdownRequested_ is false, the function is a no-op.
 * @pre     HandleInitialize() has been called.
 * @post    isRunning_ == false; shutdownRequested_ == true; all buffers are empty
 *          on success; EnforceStopOnRamCleanupFailure() called on cleanup failure.
 * @throws  None.
 * @note    Called by: Main on ECU shutdown event.
 * @warning This method discards all in-flight transmission data. Ensure DAQ has
 *          acknowledged any critical data before invoking shutdown.
 * @requirements SWR-REQ-01-09-001;SWR-REQ-01-09-002;SWR-REQ-03-13-001;
 *               SWR-REQ-03-13-002;SWR-REQ-03-13-003;SWR-REQ-01-08-003
 * @see     HandleTerminate, ClearAllTemporaryData, EnforceStopOnRamCleanupFailure
 */
void ProbeApp::HandleShutdown() noexcept
{
    // Check if shutdown has been requested
    if (shutdownRequested_.load() == true) {

        // Stop all cyclic and event-based processing
        isRunning_.store(false);

        // Delegate full buffer purge to ClearAllTemporaryData()
        ClearAllTemporaryData();

        // Evaluate cleanup result by verifying all buffers are empty
        bool cleanupResult{false};
        {
            const std::lock_guard<std::mutex> lock100ms{bufferMutex100ms_null};
            const std::lock_guard<std::mutex> lock1000ms{bufferMutex1000ms_null};
            const std::lock_guard<std::mutex> lockLog{logBufferMutex_null};

            cleanupResult =
                canBuffer100ms_null.empty() &&
                canBuffer1000ms_null.empty() &&
                logDataSetBuffer_null.empty() &&
                steadyStateDataBuffer100ms_null.empty() &&
                steadyStateDataBuffer1000ms_null.empty() &&
                eventSendingBuffer_null.empty() &&
                imageDataBuffer_null.empty();
        }

        if (cleanupResult == false) {
            // Halt application to prevent inconsistent state
            EnforceStopOnRamCleanupFailure();
        }
        // else: Normal termination path; all buffers cleared. No further action required.

    } else {
        // Shutdown not yet requested; no-op. Return without action.
    }
}

// =============================================================================
// CollectSharedMemReadSignals
// =============================================================================

/**
 * @brief   Reads CAN and internal signals from shared memory at configured
 *          sampling rates.
 * @details Increments msCounter_ by 100 on each 100 ms invocation and resets it
 *          to zero at the 1000 ms LCM boundary to prevent overflow. Dispatches to
 *          StoreCanData100ms() on every invocation (100 ms boundary is always active).
 *          Dispatches to StoreCanData1000ms() only when msCounter_ resets to zero,
 *          indicating the 1000 ms boundary has been reached. Acts purely as a
 *          scheduling dispatcher; no business logic is performed here.
 * @pre     isRunning_ == true; canConsumer_ pointer is valid.
 * @post    msCounter_ is updated; StoreCanData100ms() has been called;
 *          StoreCanData1000ms() has been called if msCounter_ == 0 after increment.
 * @throws  None.
 * @note    Called by: ProbeApp::Run() every 100 ms cycle.
 * @requirements SWR-REQ-01-01-001;SWR-REQ-01-001;SWR-REQ-01-002;SWR-REQ-01-003
 * @see     StoreCanData100ms, StoreCanData1000ms
 */
void ProbeApp::CollectSharedMemReadSignals() noexcept
{
    // Increment cycle counter by 100 ms step
    msCounter_ = msCounter_ + 100U;

    // Reset counter at LCM boundary (1000 ms) to prevent overflow
    if (msCounter_ >= 1000U) {
        msCounter_ = 0U;
    }

    // 100 ms boundary is always active on every invocation
    StoreCanData100ms();

    // 1000 ms boundary: check modulo condition (counter reset to 0 indicates 1000 ms elapsed)
    if (msCounter_ == 0U) {
        StoreCanData1000ms();
    }
    // else: No-op for 1000 ms path this cycle
}

// =============================================================================
// StoreCanData100ms
// =============================================================================

/**
 * @brief   Reads CAN signals at 100 ms rate and stores them into the 100 ms ring
 *          buffer with timestamp.
 * @details Invokes canConsumer_->ReadCanData100ms() to retrieve the latest CAN signal
 *          data from shared memory. Validates that signalData is not empty before
 *          proceeding. Acquires bufferMutex100ms_ via std::lock_guard, pops the oldest
 *          entry from canBuffer100ms_null if the buffer is at capacity
 *          (size >= kMaxBuffer100ms), and pushes the new signal entry to the back.
 *          The mutex is released automatically by RAII on scope exit.
 *          If signalData is empty, the buffer is not modified and the function returns.
 * @pre     canConsumer_ != nullptr; bufferMutex100ms_null is not held by the caller.
 * @post    canBuffer100ms_null contains one additional timestamped entry (or oldest
 *          entry overwritten if buffer was full), unless signalData was empty.
 * @throws  None.
 * @note    Called by: ProbeApp::CollectSharedMemReadSignals() every 100 ms.
 * @requirements SWR-REQ-01-001;SWR-REQ-01-01-001;SWR-REQ-01-01-002;SWR-REQ-01-003
 * @see     StoreCanData1000ms, CollectSharedMemReadSignals
 */
void ProbeApp::StoreCanData100ms() noexcept
{
    // Read CAN signals at 100 ms rate from shared memory
    const std::vector<uint8_t> signalData{canConsumer_->ReadCanData100ms()};

    // Validate acquired data before buffering
    if (!signalData.empty()) {

        // Acquire mutex for thread-safe buffer access (RAII — released on scope exit)
        const std::lock_guard<std::mutex> lock{bufferMutex100ms_null};

        // Discard oldest entry if buffer is at maximum capacity
        if (canBuffer100ms_null.size() >= static_cast<std::size_t>(kMaxBuffer100ms)) {
            canBuffer100ms_null.erase(canBuffer100ms_null.begin());
        }
        // else: Buffer not full; no discard needed

        // Insert newly acquired sample at back of ring buffer
        canBuffer100ms_null.push_back(signalData);

    }
    // else: No valid data returned; no-op; buffer unchanged
}

// =============================================================================
// StoreCanData1000ms
// =============================================================================

/**
 * @brief   Reads CAN signals at 1000 ms rate and stores them into the 1000 ms ring
 *          buffer with timestamp.
 * @details Performs a deterministic five-step sequence:
 *            1. Initialises a local canSignalEntry (std::vector<uint8_t>) to zero state.
 *            2. Calls canConsumer_->ReadCanData1000ms() to acquire the raw signal payload.
 *            3. Assigns the payload (or empty vector on failure) to canSignalEntry.data.
 *            4. Attaches the acquisition timestamp via canConsumer_->CollectTimestamp().
 *            5. Under bufferMutex1000ms_null lock, enforces ring buffer capacity by
 *               popping the front if full, then pushes the new entry to the back.
 *          If ReadCanData1000ms returns an empty vector, a zero-length data payload
 *          is stored alongside a valid timestamp to preserve buffer consistency.
 *          No dynamic allocation beyond fixed deque operations; no loops; bounded execution.
 * @pre     canConsumer_ != nullptr; bufferMutex1000ms_null is not held by the caller.
 * @post    canBuffer1000ms_null contains one additional timestamped entry (or oldest
 *          entry overwritten if buffer was full).
 * @throws  None.
 * @note    Called by: ProbeApp::CollectSharedMemReadSignals() every 1000 ms.
 * @requirements SWR-REQ-01-002;SWR-REQ-01-01-001;SWR-REQ-01-01-002;SWR-REQ-01-003
 * @see     StoreCanData100ms, CollectSharedMemReadSignals
 */
void ProbeApp::StoreCanData1000ms() noexcept
{
    // Step 1: Initialize local signal entry to zero state
    // canSignalEntry holds the assembled {timestamp, data} as a flat byte vector.
    // Layout: [timestamp_bytes(8)] + [signal_data_bytes(N)]
    std::vector<uint8_t> canSignalEntry;

    // Step 2: Read 1000 ms CAN signals from shared memory via CanConsumer
    const std::vector<uint8_t> localSignalData{canConsumer_->ReadCanData1000ms()};

    // Step 3: Check if signal data was returned successfully
    // Assign payload regardless (empty or populated) to preserve buffer consistency
    if (localSignalData.empty()) {
        // Assign zero-length payload; timestamp still valid
        canSignalEntry = localSignalData;  // empty vector
    } else {
        canSignalEntry = localSignalData;
    }

    // Step 4: Attach acquisition timestamp from CanConsumer
    // Encode timestamp as 8 bytes (uint64_t, little-endian) prepended to the entry
    const uint64_t timestamp{canConsumer_->CollectTimestamp()};
    std::vector<uint8_t> timestampedEntry;
    timestampedEntry.reserve(sizeof(uint64_t) + canSignalEntry.size());

    // Encode timestamp bytes (little-endian)
    for (std::size_t byteIdx{0U}; byteIdx < sizeof(uint64_t); ++byteIdx) {
        const uint8_t tsByte{static_cast<uint8_t>(
            (timestamp >> (byteIdx * 8U)) & 0xFFU)};
        timestampedEntry.push_back(tsByte);
    }

    // Append signal data bytes
    for (const uint8_t dataByte : canSignalEntry) {
        timestampedEntry.push_back(dataByte);
    }

    // Step 5: Lock buffer mutex for thread-safe update (RAII)
    {
        const std::lock_guard<std::mutex> lock{bufferMutex1000ms_null};

        // Step 6: Enforce ring buffer capacity — remove oldest if full
        if (canBuffer1000ms_null.size() >= static_cast<std::size_t>(kMaxBuffer1000ms)) {
            canBuffer1000ms_null.erase(canBuffer1000ms_null.begin());
        }

        // Step 7: Insert new entry at back of ring buffer
        canBuffer1000ms_null.push_back(timestampedEntry);
    }
    // Step 8: Return — no output; state is held in canBuffer1000ms_null
}

